import ast


# Whitelist of allowed built-in functions for use in expressions
ALLOWED_BUILTINS = {
    'str', 'int', 'float', 'len', 'max', 'min', 'abs', 'round', 'sum',
    'bool', 'list', 'dict', 'tuple', 'set', 'frozenset', 'enumerate',
    'zip', 'map', 'filter', 'all', 'any', 'sorted', 'reversed',
    'isinstance', 'hasattr', 'getattr', 'setattr', 'delattr',
    'True', 'False', 'None'
}


class SafeExpressionValidator(ast.NodeVisitor):
    """
    Validates that an AST expression contains only safe operations.
    Disallows attribute access, imports, lambdas, and arbitrary function calls
    to prevent sandbox escape and arbitrary code execution.
    """

    def __init__(self):
        self.safe = True
        self.allowed_names = ALLOWED_BUILTINS | {'input_data'}

    def visit_Name(self, node):
        """Only allow references to input_data and whitelisted builtins."""
        if node.id not in self.allowed_names:
            self.safe = False
        self.generic_visit(node)

    def visit_Attribute(self, node):
        """Disallow attribute access (e.g., __class__, __bases__, __subclasses__) 
        to prevent exploitation of Python's object model."""
        self.safe = False
        self.generic_visit(node)

    def visit_Call(self, node):
        """Only allow calls to whitelisted builtin functions by name.
        Disallows method calls (obj.method()) and calls to arbitrary functions."""
        if isinstance(node.func, ast.Name):
            if node.func.id not in ALLOWED_BUILTINS:
                self.safe = False
        else:
            # Disallow complex call expressions like (lambda: None)() or obj.method()
            self.safe = False

        # Validate arguments recursively
        for arg in node.args:
            self.visit(arg)
        for keyword in node.keywords:
            self.visit(keyword.value)

    def visit_Import(self, node):
        self.safe = False

    def visit_ImportFrom(self, node):
        self.safe = False

    def visit_Lambda(self, node):
        self.safe = False

    def visit_Yield(self, node):
        self.safe = False

    def visit_YieldFrom(self, node):
        self.safe = False

    def generic_visit(self, node):
        if not self.safe:
            return
        super().generic_visit(node)


def transform_step_data(transform_map_expr: str, input_data: dict) -> dict:
    """
    Transforms input data using a provided expression string.

    Args:
        transform_map_expr: A string representing a Python dictionary literal
                           that defines how to map input fields to output fields.
        input_data: Dictionary containing the input data from a previous step.

    Returns:
        A new dictionary with transformed data according to the expression.

    Raises:
        ValueError: If the expression contains unsafe operations, invalid syntax,
                   or does not evaluate to a dictionary.
    """
    try:
        # Parse the expression into an Abstract Syntax Tree (AST)
        tree = ast.parse(transform_map_expr, mode='eval')
    except SyntaxError as e:
        raise ValueError(f"Invalid expression syntax: {e}")

    # Validate the AST to ensure only safe operations are present
    validator = SafeExpressionValidator()
    validator.visit(tree)

    if not validator.safe:
        raise ValueError(
            "Expression contains unsafe operations. Only arithmetic, comparison, "
            "logical operators, dictionary/list literals, subscript access "
            "(input_data['key']), and whitelisted functions are allowed."
        )

    # Prepare restricted evaluation environment
    # Empty __builtins__ prevents access to dangerous functions like __import__, open, eval, exec
    safe_globals = {"__builtins__": {}}
    safe_locals = {"input_data": input_data}

    # Add whitelisted builtins to local scope
    import builtins
    for name in ALLOWED_BUILTINS:
        if hasattr(builtins, name):
            safe_locals[name] = getattr(builtins, name)

    # Compile and evaluate the sanitized expression
    compiled = compile(tree, filename="<string>", mode="eval")
    result = eval(compiled, safe_globals, safe_locals)

    # Ensure the result is a dictionary as specified by the function signature
    if not isinstance(result, dict):
        raise ValueError(
            f"Expression must evaluate to a dictionary, got {type(result).__name__}"
        )

    return result

"""
Workflow data transformation module for processing step outputs.
"""

import ast
import operator
from typing import Any, Dict


# Mapping of AST operator nodes to actual functions
_OPERATORS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
    ast.FloorDiv: operator.floordiv,
    ast.Mod: operator.mod,
    ast.Pow: operator.pow,
    ast.USub: operator.neg,
    ast.UAdd: operator.pos,
    ast.Eq: operator.eq,
    ast.NotEq: operator.ne,
    ast.Lt: operator.lt,
    ast.LtE: operator.le,
    ast.Gt: operator.gt,
    ast.GtE: operator.ge,
    ast.Is: operator.is_,
    ast.IsNot: operator.is_not,
    ast.In: lambda x, y: x in y,
    ast.NotIn: lambda x, y: x not in y,
}


class SafeEvaluator(ast.NodeVisitor):
    """
    A safe evaluator that only permits specific AST node types to prevent
    arbitrary code execution. Supports literals, arithmetic, comparisons,
    logical operations, and subscript access on input_data.
    """

    def __init__(self, input_data: dict):
        self.input_data = input_data
        self.allowed_names = {
            'input_data': input_data,
            'True': True,
            'False': False,
            'None': None
        }

    def visit(self, node: ast.AST) -> Any:
        if isinstance(node, ast.Expression):
            return self.visit(node.body)

        # Literals
        elif isinstance(node, ast.Constant):  # Python 3.8+
            return node.value
        elif isinstance(node, ast.Num):  # Python < 3.8
            return node.n
        elif isinstance(node, ast.Str):  # Python < 3.8
            return node.s
        elif isinstance(node, ast.NameConstant):  # Python < 3.8 (True, False, None)
            return node.value

        # Variables (only input_data and constants allowed)
        elif isinstance(node, ast.Name):
            if node.id in self.allowed_names:
                return self.allowed_names[node.id]
            raise ValueError(f"Undefined variable: {node.id}")

        # Collection literals
        elif isinstance(node, ast.Dict):
            keys = [self.visit(k) for k in node.keys]
            values = [self.visit(v) for v in node.values]
            return dict(zip(keys, values))
        elif isinstance(node, ast.List):
            return [self.visit(e) for e in node.elts]
        elif isinstance(node, ast.Tuple):
            return tuple(self.visit(e) for e in node.elts)
        elif isinstance(node, ast.Set):
            return {self.visit(e) for e in node.elts}

        # Subscript/indexing (e.g., input_data['key'])
        elif isinstance(node, ast.Subscript):
            value = self.visit(node.value)
            if isinstance(node.slice, ast.Constant):
                slice_val = node.slice.value
            elif hasattr(node.slice, 'value'):  # Python < 3.9 (ast.Index)
                slice_val = self.visit(node.slice.value)
            else:
                slice_val = self.visit(node.slice)
            return value[slice_val]

        # Arithmetic operations
        elif isinstance(node, ast.BinOp):
            left = self.visit(node.left)
            right = self.visit(node.right)
            op_type = type(node.op)
            if op_type not in _OPERATORS:
                raise ValueError(f"Unsupported binary operator: {op_type.__name__}")
            return _OPERATORS[op_type](left, right)

        # Unary operations (e.g., -x, not x)
        elif isinstance(node, ast.UnaryOp):
            operand = self.visit(node.operand)
            op_type = type(node.op)
            if op_type not in _OPERATORS:
                raise ValueError(f"Unsupported unary operator: {op_type.__name__}")
            return _OPERATORS[op_type](operand)

        # Comparison operations
        elif isinstance(node, ast.Compare):
            left = self.visit(node.left)
            for op, comparator in zip(node.ops, node.comparators):
                right = self.visit(comparator)
                op_type = type(op)
                if op_type not in _OPERATORS:
                    raise ValueError(f"Unsupported comparison operator: {op_type.__name__}")
                if not _OPERATORS[op_type](left, right):
                    return False
                left = right
            return True

        # Logical operations (and, or)
        elif isinstance(node, ast.BoolOp):
            values = [self.visit(v) for v in node.values]
            if isinstance(node.op, ast.And):
                return all(values)
            elif isinstance(node.op, ast.Or):
                return any(values)
            else:
                raise ValueError(f"Unsupported boolean operator: {type(node.op).__name__}")

        # Conditional expressions (x if condition else y)
        elif isinstance(node, ast.IfExp):
            test = self.visit(node.test)
            return self.visit(node.body) if test else self.visit(node.orelse)

        else:
            # Explicitly disallow: Call (function calls), Attribute (attribute access), 
            # Lambda, comprehensions, etc.
            raise ValueError(f"Unsupported expression type: {type(node).__name__}")


def transform_step_data(transform_map_expr: str, input_data: dict) -> dict:
    """
    Transforms input data using a provided expression string.

    Args:
        transform_map_expr: A string representing a Python dictionary literal
                           that defines how to map input fields to output fields.
        input_data: Dictionary containing the input data from a previous step.

    Returns:
        A new dictionary with transformed data according to the expression.

    Raises:
        ValueError: If the expression is invalid, unsafe, or does not evaluate to a dict.
    """
    try:
        # Parse the expression into an AST (mode='eval' ensures it's a single expression)
        tree = ast.parse(transform_map_expr, mode='eval')

        # Evaluate using the safe evaluator
        evaluator = SafeEvaluator(input_data)
        result = evaluator.visit(tree)

        # Ensure result is a dictionary as per function signature
        if not isinstance(result, dict):
            raise ValueError("Expression must evaluate to a dictionary")

        return result
    except Exception as e:
        raise ValueError(f"Invalid transformation expression: {e}")
